targets.expr:
count(
  count by (label_app_kubernetes_io_name) (
    kube_pod_labels{
      label_app_kubernetes_io_component="scr"
    }
    * on (pod, namespace) group_left()
    max by (pod, namespace) (
      kube_pod_container_status_ready == 1
    )
  )
)

sum(
  node_namespace_pod_container:container_cpu_usage_seconds_total:sum_rate5m{cluster="$cluster", namespace="$namespace"}
  * on (namespace, pod)
    group_left
    kube_pod_labels{
      label_app_kubernetes_io_name=~"$model"
    }
 * 1000) by (pod)

sum(
  cluster:namespace:pod_cpu:active:kube_pod_container_resource_requests{
    cluster="$cluster",
    namespace="$namespace"
  }
  * on (namespace, pod)
    group_left
    kube_pod_labels{
      label_app_kubernetes_io_name=~"$model"
    }
 * 1000) by (pod)

sum(cluster:namespace:pod_cpu:active:kube_pod_container_resource_limits{cluster="$cluster", namespace="$namespace"}
  * on (namespace, pod)
    group_left
    kube_pod_labels{
      label_app_kubernetes_io_name=~"$model"
    }
 * 1000) by (pod)

sum(container_memory_working_set_bytes{job="kubelet", metrics_path="/metrics/cadvisor", cluster="$cluster", namespace="$namespace",container!="", image!=""}
  * on (namespace, pod)
    group_left
    kube_pod_labels{
      label_app_kubernetes_io_name=~"$model"
    }
) by (pod)

